class Solution:
    def maxSum(self, nums: List[int]) -> int:
        max_digits = {}
        for num in nums:
            max_d = max(int(d) for d in str(num))
            if max_d not in max_digits:
                max_digits[max_d] = []
            max_digits[max_d].append(num)

        result = -1
        for key in max_digits:
            nums_list = max_digits[key]
            if len(nums_list) >= 2:
                current_max = sum(sorted(nums_list, reverse=True)[:2])
                result = max(result, current_max)

        return result
